oldWay:
/* .prose h2 has specificity (0,1,1) */
.prose h2 { color: #a855f7; }

/* .highlight only has (0,1,0) — it LOSES */
.highlight { color: #22d3ee; }

/* Fix required !important or more specific overrides */
.prose h2.highlight { color: #22d3ee; }

modernWay:
/* :where(.prose) h2 has specificity (0,0,1) */
:where(.prose) h2 { color: #a855f7; }

/* .highlight has (0,1,0) — it WINS */
.highlight { color: #22d3ee; }

startingCSS:
.prose {
  padding: 1.5rem;
  background: #1e293b;
  border-radius: 10px;
}

/* Base heading style — use :where() so .highlight can override it */
/* :where(.prose) h2 { color: #a855f7; margin: 0 0 0.75rem; font-size: 1rem; } */

.highlight {
  color: #22d3ee;
}
